import{_ as o,o as t,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Loki","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/grafana/loki/README.md","filePath":"software-engineering/grafana/loki/README.md"}'),i={name:"software-engineering/grafana/loki/README.md"};function n(l,e,s,c,d,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="loki" tabindex="-1">Loki <a class="header-anchor" href="#loki" aria-label="Permalink to &quot;Loki&quot;">​</a></h1><h2 id="meet-grafana-loki-a-log-aggregation-system-for-everything" tabindex="-1">Meet Grafana LOKI, a Log Aggregation System for Everything <a class="header-anchor" href="#meet-grafana-loki-a-log-aggregation-system-for-everything" aria-label="Permalink to &quot;Meet Grafana LOKI, a Log Aggregation System for Everything&quot;">​</a></h2><p>By <a href="https://l.technotim.live/twitter" target="_blank" rel="noreferrer"><em>Techno Tim</em></a>Posted <em>4 months ago</em> Updated <em>12 days ago</em> <em>4 min</em> read</p><p><a href="https://www.youtube.com/watch?v=h_GGd7HfKQ8" target="_blank" rel="noreferrer"><img src="https://img.youtube.com/vi/h_GGd7HfKQ8/0.jpg" alt="Meet Grafana LOKI, a Log Aggregation System for Everything"></a></p><p>I’ve been on a quest to find a new logging system. I’ve use quite a few in the past, some open source, some proprietary, and some home grown, but recently I’ve decided to switch. I’ve switched to Grafana Loki for all of my logs for all of my systems - this includes machines, devices, docker systems and hosts, and my all of my kubernetes clusters. If you’re thinking of using Grafana and are also looking for a fast way to log all of your systems, join me as we discuss and configure Grafana Loki</p><p>Don’t want to host it yourself? Check out Grafana Cloud and sign up for a free account <a href="https://l.technotim.live/grafana-labs" target="_blank" rel="noreferrer">https://l.technotim.live/grafana-labs</a></p><p>See all the hardware I recommend at <a href="https://l.technotim.live/gear" target="_blank" rel="noreferrer">https://l.technotim.live/gear</a></p><p>Don’t forget to check out the <a href="https://l.technotim.live/quick-start" target="_blank" rel="noreferrer">🚀Launchpad repo</a> with all of the quick start source files.</p><h3 id="docker-setup" tabindex="-1">Docker Setup <a href="#docker-setup" id="docker-setup"></a> <a class="header-anchor" href="#docker-setup" aria-label="Permalink to &quot;Docker Setup &lt;a href=&quot;#docker-setup&quot; id=&quot;docker-setup&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>See <a href="https://docs.technotim.live/posts/docker-compose-install/" target="_blank" rel="noreferrer">this post</a> on how to install <code>docker</code> and <code>docker-compose</code></p><h3 id="running-the-container" tabindex="-1">Running the container <a href="#running-the-container" id="running-the-container"></a> <a class="header-anchor" href="#running-the-container" aria-label="Permalink to &quot;Running the container &lt;a href=&quot;#running-the-container&quot; id=&quot;running-the-container&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>If you’re using Docker compose</p><p><code>docker-compose.yml</code></p><h3 id="loki-config" tabindex="-1">Loki Config <a href="#loki-config" id="loki-config"></a> <a class="header-anchor" href="#loki-config" aria-label="Permalink to &quot;Loki Config &lt;a href=&quot;#loki-config&quot; id=&quot;loki-config&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><code>loki-config.yml</code></p><h3 id="promtail-config" tabindex="-1">Promtail Config <a href="#promtail-config" id="promtail-config"></a> <a class="header-anchor" href="#promtail-config" aria-label="Permalink to &quot;Promtail Config &lt;a href=&quot;#promtail-config&quot; id=&quot;promtail-config&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><code>promtail-config.yml</code></p><h3 id="loki-docker-driver" tabindex="-1">Loki Docker Driver <a href="#loki-docker-driver" id="loki-docker-driver"></a> <a class="header-anchor" href="#loki-docker-driver" aria-label="Permalink to &quot;Loki Docker Driver &lt;a href=&quot;#loki-docker-driver&quot; id=&quot;loki-docker-driver&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Install docker plugin</p><p>Edit docker daemon config</p><p><code>daemon.json</code></p><p>Restart docker daemon.</p><p>You will also need to recreate your containers after applying this setting *</p><h3 id="logql-sample-queries" tabindex="-1">LogQL sample queries <a href="#logql-sample-queries" id="logql-sample-queries"></a> <a class="header-anchor" href="#logql-sample-queries" aria-label="Permalink to &quot;LogQL sample queries &lt;a href=&quot;#logql-sample-queries&quot; id=&quot;logql-sample-queries&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Query all logs from the <code>varlogs</code> stream</p><p>Query all logs from the <code>varlogs</code> stream and filter on <code>docker</code></p><p>Query all logs from the <code>container_name</code> label of <code>uptime-kuma</code> and filter on <code>host</code> of <code>juno</code></p><p>Read more about LogQL <a href="https://grafana.com/docs/loki/latest/logql/" target="_blank" rel="noreferrer">here</a></p><h3 id="arm-cpu-raspberry-pi" tabindex="-1">ARM CPU (Raspberry Pi) <a href="#arm-cpu-raspberry-pi" id="arm-cpu-raspberry-pi"></a> <a class="header-anchor" href="#arm-cpu-raspberry-pi" aria-label="Permalink to &quot;ARM CPU (Raspberry Pi) &lt;a href=&quot;#arm-cpu-raspberry-pi&quot; id=&quot;arm-cpu-raspberry-pi&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>There is a workaround for using this with ARM CPUs. Credit to <a href="https://github.com/AndreiTelteu" target="_blank" rel="noreferrer">AndreiTelteu</a> for finding this <a href="https://github.com/techno-tim/techno-tim.github.io/discussions/97" target="_blank" rel="noreferrer">in this discussion</a></p><p>delete <code>/etc/docker/daemon.json</code></p><p>Add the vector service to the docker-compose.yml file</p><p>Run this command</p><p>paste this config in the file:</p><p>Credits to this post for the config file: <a href="https://github.com/grafana/loki/issues/2361#issuecomment-826732810" target="_blank" rel="noreferrer">grafana/loki#2361 (comment)</a></p><h3 id="kubernetes-setup" tabindex="-1">Kubernetes Setup <a href="#kubernetes-setup" id="kubernetes-setup"></a> <a class="header-anchor" href="#kubernetes-setup" aria-label="Permalink to &quot;Kubernetes Setup &lt;a href=&quot;#kubernetes-setup&quot; id=&quot;kubernetes-setup&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>If you’re looking to set this up in kubernetes, see <a href="https://docs.technotim.live/posts/grafana-loki-kubernetes/" target="_blank" rel="noreferrer">this post</a></p><br>',38)])])}const g=o(i,[["render",n]]);export{p as __pageData,g as default};
